import React, { useState } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  CreditCard as CardIcon, Eye, Download, X, Save, ShieldAlert, Landmark, Menu, FileText, Calendar, Clock, Check, XCircle
} from 'lucide-react';

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');
  
  // --- Updated Data Engine (Aligned with SRS) ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, name: 'Rajesh Kumar', room: 'A-101', 
      status: 'No Request', // Statuses: No Request, Pending Approval, Approved, Rejected
      rentAmount: 12500,
      electricity: { old: 1050, current: 0, pricePerUnit: 8, units: 0, total: 0, isGenerated: false },
      lastPayment: null,
      phone: '+91 98765 43210'
    }
  ]);

  const [notifications, setNotifications] = useState([
    { id: 1, title: 'System Ready', desc: 'SRS v2.0 Logic Engaged.', time: 'Just now', type: 'info' }
  ]);

  // 2.1.1 & 2.1.2: Payment Request & Approval Flow
  const handlePaymentRequest = (tenantId) => {
    setTenants(prev => prev.map(t => t.id === tenantId ? { ...t, status: 'Pending Approval' } : t));
    setNotifications(prev => [{
      id: Date.now(),
      title: 'New Payment Request',
      desc: `Tenant in ${tenants.find(t => t.id === tenantId).room} is asking for approval.`,
      time: 'Just now',
      type: 'alert'
    }, ...prev]);
  };

  const handleApproval = (tenantId, decision) => {
    const status = decision === 'Approve' ? 'Approved' : 'Rejected';
    const today = new Date().toLocaleString();
    
    setTenants(prev => prev.map(t => t.id === tenantId ? { 
      ...t, 
      status: status,
      lastPayment: status === 'Approved' ? { date: today, amount: t.rentAmount + t.electricity.total } : t.lastPayment
    } : t));
  };

  // 2.2.2: Electricity Bill Calculation Logic
  const calculateElectricity = (tenantId, currentReading, price) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        const units = currentReading - t.electricity.old;
        const total = units * price;
        return { 
          ...t, 
          electricity: { ...t.electricity, current: currentReading, units, total, pricePerUnit: price, isGenerated: true } 
        };
      }
      return t;
    }));
  };

  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl">
          <div className="flex justify-center mb-8">
             <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-white text-2xl font-black italic">H</div>
          </div>
          <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-8">
            <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-lg' : 'text-slate-400'}`}>Resident</button>
            <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-lg' : 'text-slate-400'}`}>Landlord</button>
          </div>
          <button onClick={() => setUserRole(loginMode)} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-widest text-xs hover:bg-indigo-600 transition-all">Enter Portal</button>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} calculateElectricity={calculateElectricity} handleApproval={handleApproval} notifications={notifications} logout={() => setUserRole(null)} />
  ) : (
    <TenantPortal tenant={tenants[0]} handleRequest={() => handlePaymentRequest(tenants[0].id)} logout={() => setUserRole(null)} />
  );
};

// --- LANDLORD SIDE ---
const AdminPortal = ({ tenants, calculateElectricity, handleApproval, notifications, logout }) => {
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [meterInput, setMeterInput] = useState({ id: 1, reading: '', price: 8 });

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className="w-72 bg-slate-900 text-white p-8 flex flex-col hidden md:flex">
        <div className="font-black italic text-xl mb-12">HOMELY ADMIN</div>
        <nav className="space-y-2">
          {['Dashboard', 'Electricity', 'Approvals'].map(t => (
            <button key={t} onClick={() => setActiveTab(t)} className={`w-full text-left px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeTab === t ? 'bg-indigo-600' : 'text-slate-500'}`}>{t}</button>
          ))}
          <button onClick={logout} className="w-full text-left px-6 py-4 text-red-400 text-[10px] font-black uppercase tracking-widest">Logout</button>
        </nav>
      </aside>

      <main className="flex-1 p-12 overflow-y-auto">
        {activeTab === 'Dashboard' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black italic uppercase">Overview</h2>
            <div className="grid grid-cols-2 gap-6">
              <div className="bg-white p-8 rounded-[2rem] border shadow-sm">
                <p className="text-[10px] font-black text-slate-400 uppercase">Total Revenue</p>
                <h3 className="text-4xl font-black italic text-indigo-600">₹{tenants.reduce((acc, t) => acc + (t.status === 'Approved' ? t.rentAmount : 0), 0)}</h3>
              </div>
              <div className="bg-white p-8 rounded-[2rem] border shadow-sm">
                <p className="text-[10px] font-black text-slate-400 uppercase">Pending Approvals</p>
                <h3 className="text-4xl font-black italic text-orange-500">{tenants.filter(t => t.status === 'Pending Approval').length}</h3>
              </div>
            </div>
          </div>
        )}

        {/* 2.2.1: Meter Reading Input */}
        {activeTab === 'Electricity' && (
          <div className="max-w-2xl bg-white p-10 rounded-[3rem] border shadow-sm space-y-8">
            <h3 className="text-xl font-black italic uppercase flex items-center gap-2"><Zap className="text-yellow-500"/> Billing Module</h3>
            {tenants.map(t => (
              <div key={t.id} className="p-6 bg-slate-50 rounded-2xl space-y-4">
                <div className="flex justify-between font-bold"><span>{t.name} ({t.room})</span> <span>Old Reading: {t.electricity.old}</span></div>
                <div className="grid grid-cols-2 gap-4">
                  <input type="number" placeholder="Current Reading" className="p-4 rounded-xl border-none outline-indigo-600 font-bold" onChange={(e) => setMeterInput({...meterInput, reading: e.target.value})} />
                  <input type="number" placeholder="Price/Unit" defaultValue={8} className="p-4 rounded-xl border-none outline-indigo-600 font-bold" onChange={(e) => setMeterInput({...meterInput, price: e.target.value})} />
                </div>
                <button onClick={() => calculateElectricity(t.id, meterInput.reading, meterInput.price)} className="w-full py-4 bg-indigo-600 text-white rounded-xl font-black uppercase text-[10px]">Generate & Push Bill</button>
              </div>
            ))}
          </div>
        )}

        {/* 2.1.2: Payment Approval Flow */}
        {activeTab === 'Approvals' && (
          <div className="space-y-6">
            <h3 className="text-xl font-black italic uppercase">Review Requests</h3>
            {tenants.filter(t => t.status === 'Pending Approval').map(t => (
              <div key={t.id} className="bg-white p-8 rounded-[2.5rem] border flex items-center justify-between animate-pulse">
                <div>
                  <p className="font-black text-lg italic">{t.name}</p>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">Rent: ₹{t.rentAmount} + Elec: ₹{t.electricity.total}</p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => handleApproval(t.id, 'Approve')} className="p-4 bg-emerald-500 text-white rounded-2xl"><Check/></button>
                  <button onClick={() => handleApproval(t.id, 'Reject')} className="p-4 bg-red-500 text-white rounded-2xl"><X/></button>
                </div>
              </div>
            ))}
            {tenants.filter(t => t.status === 'Pending Approval').length === 0 && <p className="text-slate-400 font-black italic">No pending requests.</p>}
          </div>
        )}
      </main>
    </div>
  );
};

// --- TENANT SIDE ---
const TenantPortal = ({ tenant, handleRequest, logout }) => {
  return (
    <div className="min-h-screen bg-slate-50 p-6 md:p-12 font-sans">
      <div className="max-w-4xl mx-auto space-y-8">
        <header className="flex justify-between items-center mb-12">
           <div className="text-2xl font-black italic text-indigo-600">MY HOME</div>
           <button onClick={logout} className="p-4 bg-white rounded-2xl border text-red-500 shadow-sm"><LogOut size={20}/></button>
        </header>

        {/* 2.2.3: Electricity Record Features (Tenant View) */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-white p-10 rounded-[3rem] border shadow-sm">
            <h4 className="text-[10px] font-black text-slate-400 uppercase mb-6 italic">Electricity Breakdown</h4>
            <div className="space-y-4">
              <div className="flex justify-between text-xs font-bold"><span>Reading (Old/New)</span> <span>{tenant.electricity.old} / {tenant.electricity.current || '---'}</span></div>
              <div className="flex justify-between text-xs font-bold"><span>Units Consumed</span> <span>{tenant.electricity.units}</span></div>
              <div className="flex justify-between text-xl font-black italic text-indigo-600 border-t pt-4"><span>Elec. Bill</span> <span>₹{tenant.electricity.total}</span></div>
            </div>
          </div>

          {/* 2.1.3: Payment Status Tracking */}
          <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl">
             <p className="text-[10px] font-black text-indigo-300 uppercase mb-4 italic">Status: {tenant.status}</p>
             <h2 className="text-5xl font-black italic mb-8">₹{tenant.rentAmount + tenant.electricity.total}</h2>
             
             {tenant.status === 'No Request' || tenant.status === 'Rejected' ? (
               <button onClick={handleRequest} className="w-full py-5 bg-indigo-600 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:scale-105 transition-all">Request Approval</button>
             ) : tenant.status === 'Pending Approval' ? (
               <div className="w-full py-5 bg-orange-500/20 text-orange-400 border border-orange-500/50 rounded-2xl font-black uppercase text-xs text-center flex items-center justify-center gap-2"><Clock size={16}/> Waiting for Landlord</div>
             ) : (
               <div className="w-full py-5 bg-emerald-500 text-white rounded-2xl font-black uppercase text-xs text-center flex items-center justify-center gap-2"><CheckCircle2 size={16}/> Payment Completed</div>
             )}
          </div>
        </div>

        {/* 2.3: Receipt System (Generated on Approval) */}
        {tenant.status === 'Approved' && (
          <div className="bg-white p-12 rounded-[3rem] border-2 border-dashed border-slate-200 animate-in fade-in">
            <div className="flex justify-between items-start mb-10">
               <div><h3 className="text-2xl font-black italic uppercase">Official Receipt</h3><p className="text-[10px] font-bold text-slate-400">{tenant.lastPayment.date}</p></div>
               <CheckCircle2 className="text-emerald-500" size={40}/>
            </div>
            <div className="space-y-3 border-t border-b py-6 my-6">
               <div className="flex justify-between text-sm"><span>Base Rent</span> <span className="font-black italic">₹{tenant.rentAmount}</span></div>
               <div className="flex justify-between text-sm"><span>Electricity ({tenant.electricity.units} units)</span> <span className="font-black italic">₹{tenant.electricity.total}</span></div>
            </div>
            <div className="flex justify-between text-2xl font-black italic uppercase"><span>Total Paid</span> <span>₹{tenant.lastPayment.amount}</span></div>
            <button className="mt-8 w-full py-4 border-2 border-slate-900 rounded-xl font-black uppercase text-[10px] flex items-center justify-center gap-2"><Download size={16}/> Save as PDF</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
